import sys
import math

def solve() -> None:
    data = list(map(int, sys.stdin.read().split()))
    it = iter(data)
    t = next(it)
    out_lines = []
    for _ in range(t):
        n = next(it)
        a = [next(it) for _ in range(n)]

        cnt = [0] * 30
        for v in a:
            b = 0
            while v:
                if v & 1:
                    cnt[b] += 1
                v >>= 1
                b += 1

        g = 0
        for c in cnt:
            if c:
                g = math.gcd(g, c)

        if g == 0:                     # all zeros
            ans = list(range(1, n + 1))
        else:
            ans = []
            limit = int(math.isqrt(g))
            for d in range(1, limit + 1):
                if g % d == 0:
                    if d <= n:
                        ans.append(d)
                    d2 = g // d
                    if d2 != d and d2 <= n:
                        ans.append(d2)
            ans.sort()
        out_lines.append(' '.join(map(str, ans)))
    sys.stdout.write('\n'.join(out_lines))

