import sys

def digit_len(x: int) -> int:
    # x >= 1
    return len(str(x))

def solve() -> None:
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    t = int(next(it))
    out_lines = []
    for _ in range(t):
        x1 = int(next(it)); p1 = int(next(it))
        x2 = int(next(it)); p2 = int(next(it))

        d1 = digit_len(x1)
        d2 = digit_len(x2)

        L1 = d1 + p1
        L2 = d2 + p2

        if L1 > L2:
            out_lines.append('>')
        elif L1 < L2:
            out_lines.append('<')
        else:
            # same total length
            k = min(p1, p2)
            p1 -= k
            p2 -= k

            # now at most one of p1, p2 is non‑zero and both ≤ 6
            while p1:
                x1 *= 10
                p1 -= 1
            while p2:
                x2 *= 10
                p2 -= 1

            if x1 > x2:
                out_lines.append('>')
            elif x1 < x2:
                out_lines.append('<')
            else:
                out_lines.append('=')

    sys.stdout.write('\n'.join(out_lines))

