class DSU:
    def __init__(self, n):
        self.par = list(range(n))
        self.sz = [1] * n

    def find(self, x):
        while self.par[x] != x:
            self.par[x] = self.par[self.par[x]]
            x = self.par[x]
        return x

    def union(self, a, b):
        a = self.find(a)
        b = self.find(b)
        if a == b:
            return
        if self.sz[a] < self.sz[b]:
            a, b = b, a
        self.par[b] = a
        self.sz[a] += self.sz[b]

def solve() -> None:
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    idx = 1
    out = []
    for _ in range(t):
        s = data[idx]
        idx += 1
        n = len(s)
        dsu = DSU(n)

        # unite equal neighbours
        for i, ch in enumerate(s):
            if ch == 'E':
                dsu.union(i, (i + 1) % n)

        ok = True
        # check unequal neighbours
        for i, ch in enumerate(s):
            if ch == 'N':
                if dsu.find(i) == dsu.find((i + 1) % n):
                    ok = False
                    break

        out.append("YES" if ok else "NO")
    sys.stdout.write("\n".join(out))

